import{_ as i,o as n,c as a,ag as t}from"./chunks/framework.ePeAWSvT.js";const h=JSON.parse('{"title":"COURS : LA MÉNINGITE","description":"","frontmatter":{},"headers":[],"relativePath":"matieres/sante/cours/méningite.md","filePath":"matieres/sante/cours/méningite.md"}'),l={name:"matieres/sante/cours/méningite.md"};function r(s,e,o,u,m,c){return n(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="cours-la-meningite" tabindex="-1">COURS : LA MÉNINGITE <a class="header-anchor" href="#cours-la-meningite" aria-label="Permalink to &quot;COURS : LA MÉNINGITE&quot;">​</a></h1><h2 id="_1️⃣-definition" tabindex="-1">1️⃣ Définition <a class="header-anchor" href="#_1️⃣-definition" aria-label="Permalink to &quot;1️⃣ Définition&quot;">​</a></h2><p>La méningite est une <strong>inflammation des méninges</strong>, les membranes qui entourent le cerveau et la moelle épinière.</p><p>Elle est généralement causée par :</p><ul><li>des bactéries</li><li>des virus</li><li>plus rarement des champignons</li></ul><p>⚠️ La méningite bactérienne est une <strong>urgence médicale grave</strong>.</p><hr><h2 id="_2️⃣-types-de-meningite" tabindex="-1">2️⃣ Types de méningite <a class="header-anchor" href="#_2️⃣-types-de-meningite" aria-label="Permalink to &quot;2️⃣ Types de méningite&quot;">​</a></h2><h3 id="🔹-meningite-virale" tabindex="-1">🔹 Méningite virale <a class="header-anchor" href="#🔹-meningite-virale" aria-label="Permalink to &quot;🔹 Méningite virale&quot;">​</a></h3><ul><li>La plus fréquente</li><li>Généralement bénigne</li><li>Guérison spontanée dans la plupart des cas</li></ul><hr><h3 id="🔹-meningite-bacterienne" tabindex="-1">🔹 Méningite bactérienne <a class="header-anchor" href="#🔹-meningite-bacterienne" aria-label="Permalink to &quot;🔹 Méningite bactérienne&quot;">​</a></h3><ul><li>Plus grave</li><li>Peut entraîner des complications sévères</li><li>Nécessite un traitement urgent par antibiotiques</li></ul><hr><h2 id="_3️⃣-symptomes" tabindex="-1">3️⃣ Symptômes <a class="header-anchor" href="#_3️⃣-symptomes" aria-label="Permalink to &quot;3️⃣ Symptômes&quot;">​</a></h2><p>Les symptômes apparaissent souvent rapidement :</p><ul><li>Fièvre élevée</li><li>Maux de tête intenses</li><li>Raideur de la nuque</li><li>Vomissements</li><li>Sensibilité à la lumière (photophobie)</li><li>Confusion</li><li>Convulsions</li></ul><p>Chez l’enfant :</p><ul><li>pleurs</li><li>irritabilité</li><li>fontanelle bombée</li></ul><hr><h2 id="_4️⃣-diagnostic" tabindex="-1">4️⃣ Diagnostic <a class="header-anchor" href="#_4️⃣-diagnostic" aria-label="Permalink to &quot;4️⃣ Diagnostic&quot;">​</a></h2><ul><li>Examen clinique</li><li>Ponction lombaire</li><li>Analyse du liquide céphalorachidien</li><li>Analyse sanguine</li><li>Scanner cérébral</li></ul><hr><h2 id="_5️⃣-traitement" tabindex="-1">5️⃣ Traitement <a class="header-anchor" href="#_5️⃣-traitement" aria-label="Permalink to &quot;5️⃣ Traitement&quot;">​</a></h2><ul><li>Antibiotiques (si bactérienne)</li><li>Antiviraux dans certains cas</li><li>Antipyrétiques</li><li>Hospitalisation et surveillance</li></ul><hr><h2 id="_6️⃣-prevention" tabindex="-1">6️⃣ Prévention <a class="header-anchor" href="#_6️⃣-prevention" aria-label="Permalink to &quot;6️⃣ Prévention&quot;">​</a></h2><ul><li>Vaccination</li><li>Hygiène</li><li>Traitement préventif des contacts proches</li></ul>',28)])])}const p=i(l,[["render",r]]);export{h as __pageData,p as default};
